Use two distinct paths: bundled resources (read-only) and Application Support (writable).

```swift
public actor UserFTAIManager {
    /// READ-ONLY bundled knowledge
    private var bundledRtaiLibraryPath: String {
        if let url = Bundle.main.resourceURL {
            let path = url.appendingPathComponent("rtai-library").path
            if FileManager.default.fileExists(atPath: path) { return path }
        }
        // Dev fallback
        return "\(projectRoot)/rtai-library"
    }

    /// WRITABLE user data in Application Support
    private var userDataPath: String {
        guard let appSupport = FileManager.default.urls(
            for: .applicationSupportDirectory, in: .userDomainMask
        ).first else { return fallbackPath }
        return appSupport.appendingPathComponent("Serena/rtai-user-data").path
    }

    private var userPersonalPath: String { "\(userDataPath)/user_personal.ftai" }
    private var userPreferencesPath: String { "\(userDataPath)/user_preferences.ftai" }
}
```

FTAI file format uses sections delimited by `---`:
```
@ftai v2.0
@document
title: "User Personal Information"
@end
@facts
type: "user_personal"
last_updated: "2026-04-01"
@end
---
wife's name: Christina
favorite language: Rust
---
@query_patterns
@end
```

Facts live between the `---` markers. Metadata lives in `@document` and `@facts` blocks. This separation means bundled knowledge files can be updated via app updates without overwriting user-entered data.

Add a simple cache layer to avoid repeated file I/O on hot paths:

```swift
public actor UserFTAIManager {
    private var cachedFacts: [(key: String, value: String, category: MemoryCategory)]?
    private var cacheTimestamp: Date?
    private let cacheTTL: TimeInterval = 30  // 30 seconds

    private var isCacheValid: Bool {
        guard cachedFacts != nil, let timestamp = cacheTimestamp else { return false }
        return Date().timeIntervalSince(timestamp) < cacheTTL
    }

    private func invalidateCache() {
        cachedFacts = nil
        cacheTimestamp = nil
    }

    public func getAllFacts() async -> [(key: String, value: String, category: MemoryCategory)] {
        if isCacheValid, let cached = cachedFacts {
            return cached
        }
        var facts: [(String, String, MemoryCategory)] = []
        facts.append(contentsOf: await readFacts(from: userPersonalPath, category: .personal))
        facts.append(contentsOf: await readFacts(from: userPreferencesPath, category: .preference))
        cachedFacts = facts
        cacheTimestamp = Date()
        return facts
    }

    public func addFact(key: String, value: String, ...) async {
        // ... write to file ...
        invalidateCache()  // Bust cache on write
    }
}
```

Key design: (1) 30-second TTL is short enough that external edits to .ftai files are picked up quickly. (2) Any write operation calls `invalidateCache()` to ensure consistency. (3) The actor isolation means cache reads/writes are automatically thread-safe. (4) For LLM prompt injection, cap output at 20 facts / 2000 chars to keep context lean.

Three tiers based on priority and explicit user intent:

```swift
public func extractAndSave(from message: String) async -> [ExtractedFact] {
    let hasExplicitRemember = detectExplicitRememberCommand(message)
    var facts = await extractFacts(from: message)

    for fact in facts {
        let effectivePriority = hasExplicitRemember ? max(fact.priority, 12) : fact.priority
        var shouldStore = false

        // Rule 1: Explicit "remember" -> always store
        if hasExplicitRemember {
            shouldStore = true
        }
        // Rule 2: High-priority (>= 8, e.g. relationships) -> store immediately
        else if effectivePriority >= 8 {
            shouldStore = true
        }
        // Rule 3: Medium priority (5-7) -> track mentions, store after 5 repetitions
        else if effectivePriority >= 5 {
            let key = normalizeMentionKey(fact.fact)
            let count = (mentionCounts[key] ?? 0) + 1
            mentionCounts[key] = count
            if count >= repeatMentionThreshold {
                shouldStore = true
                mentionCounts[key] = 0  // Reset after storing
            }
        }
        // Below 5 -> discard

        if shouldStore {
            await ftaiManager.addExtractedFact(fact.fact, category: fact.category, priority: effectivePriority)
        }
    }
}
```

Priority assignments: relationships/health = 10, names = 9, work/allergies = 7-8, favorites = 5-6, casual preferences = 4. The mention tracking prevents casual mentions from polluting the fact store while still capturing consistently repeated information.

Two main tables: `sessions` (with nested `tool_calls`) and `generated_rules`:

