                arguments_summary TEXT NOT NULL, result_type TEXT NOT NULL,
                error_message TEXT, duration_ms INTEGER DEFAULT 0
            );
            CREATE TABLE IF NOT EXISTS generated_rules (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL UNIQUE, confidence REAL DEFAULT 0.0,
                ftai_rule TEXT NOT NULL, generated_at INTEGER NOT NULL,
                applied_count INTEGER DEFAULT 0, success_after_apply INTEGER DEFAULT 0,
                disabled INTEGER DEFAULT 0
            );
        ")?;
