    self.conn.prepare(
        "SELECT name, source, confidence, ftai_rule
         FROM generated_rules
         WHERE confidence >= 0.7 AND disabled = 0
         ORDER BY confidence DESC LIMIT 20"
    )?
    // ... map rows ...
