```rust
pub fn save_outcome(&self, outcome: &SessionOutcome) -> Result<()> {
    let tx = self.conn.unchecked_transaction()?;
    tx.execute("INSERT OR REPLACE INTO sessions ...", params![...]);
    tx.execute("DELETE FROM tool_calls WHERE session_id = ?1", [&outcome.session_id]);
    for (seq, tc) in outcome.tool_calls.iter().enumerate() {
        tx.execute("INSERT INTO tool_calls ...", params![...]);
    }
    tx.commit()?;
    Ok(())
}
